/* * * V I T A L S * * */
import * as React from 'react';

import './OptionsButton.css';
// Profile = 0, Social = 1, Home = 2, Macros = 3
	// there will be more for other pages: Post, UserProfile, Global, etc

export default function OptionsButton({current, setCurrent}) {

	// each object is option name and function
	const profileOptions = [
		/* 
			edit profile
			settings
		*/
		{
			name: 'editProfile',
			function: null,
			class: ''
		},
		{
			name: 'settings',
			function: null,
			class: ''
		}
	];
	const socialOptions = [
		/*
			Add to Stream
			Find & Manage
			Calendar
			Map
		*/
		{
			name: 'Find & Manage',
			function: null,
			class: ''
		},
		{
			name: 'Add to Stream',
			function: null,
			class: ''
		},
		{
			name: 'Calendar',
			function: null,
			class: ''
		},
		{
			name: 'Map',
			function: null,
			class: ''
		}
	];
	const homeOptions = [
		/*
			View Stream
			New Post
			Calendar
			Map
			Custom Feeds
		*/
		{
			name: 'New Post',
			function: null,
			class: ''
		},
		{
			name: 'View Stream',
			function: null,
			class: ''
		},
		{
			name: 'Calendar',
			function: null,
			class: ''
		},
		{
			name: 'Map',
			function: null,
			class: ''
		},
		{
			name: `Custom Log: ${current.log}`,
			function: null,
			class: ''
		},
	];
	const macrosOptions = [
		/*
			Create Tag
			Delete Tags
			New Collection
			Manage Collections
		*/
		{
			name: 'Create Tag',
			function: null,
			class: ''
		},
		{
			name: 'Delete Tags',
			function: null,
			class: ''
		},
		{
			name: 'New Collection',
			function: null,
			class: ''
		},
		{
			name: 'Manage Collections',
			function: null,
			class: ''
		},
	];
	
	const [activeSection, setActiveSection] = React.useState(2);
	const [optionsGroup, setOptionsGroup] = React.useState([profileOptions, socialOptions, homeOptions, macrosOptions]);
	const activeGroup = optionsGroup[activeSection];
	const [optionsOpen, setOptionsOpen] = React.useState(false);

	const launchOptions = () => {

		if(optionsOpen == false) {
			const newOptionsGroup = optionsGroup.map((group, index) => {
				if(index == activeSection) {
					const classifiedGroup = group().map((item, index) => ({
						...item,
						class: `active${index+1}`
					}));
					return classifiedGroup;
				}
				return group;
			})
			setOptionsGroup(newOptionsGroup);
			setOptionsOpen(true);
		}
		else if(optionsOpen == true) {
			const newOptionsGroup = optionsGroup.map((group, index) => {
				if(index == activeSection) {
					const classifiedGroup = group().map((item, index) => ({
						...item,
						class: ""
					}));
					return classifiedGroup;
				}
				return group;
			})
			setOptionsGroup(newOptionsGroup);
			setOptionsOpen(false);
		}
	}

	//Changes the activeGroup value based on current.section 
	React.useEffect(()=> {
		if(current.section == 'profile') {
			setActiveSection(0)
		}
		else if(current.section == 'social') {
			setActiveSection(1)
		}
		else if(current.section == 'home') {
			setActiveSection(2)
		}
		if(current.section == 'macros') {
			setActiveSection(3)
		}
	}, [current])


	return (

		<div id="optionsButtonWrapper">

			{optionsOpen &&
				<ul id="options">
					{activeGroup.map(option => (
						<li className={`${option.class}`}>
							<button className={`buttonDefault`}>{option.name}</button>
						</li>
					))}
				</ul>
			}
			
			<button id="main" onClick={launchOptions}></button>
		</div>

		
	)
}
